html:
{% set currency = doc.currency %}

<style>
  body {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 12px;
    color: #1c1f24;
    background: #fbfbf9;
  }

  .qd-content {
    padding: 10px;
  }

  table {
    width: 100%;
    border-collapse: collapse;
  }

  td {
    padding: 9px;
    border: 1px solid #e7eaee;
    font-size: 12px;
  }

  .right {
    text-align: right;
  }

  .qd-header-row td {
    background-color: #dff1f8;
    padding: 14px;
  }

  .qd-title {
    font-size: 26px;
    font-weight: bold;
    color: #123a4b;
  }

  .qd-subtitle {
    font-size: 12px;
    color: #355f6f;
  }

  .qd-meta {
    text-align: right;
    font-size: 12px;
  }

  .qd-card {
    border: 1px solid #e7eaee;
    padding: 14px;
    background-color: #f7fbfd;
  }

  .qd-label {
    font-size: 11px;
    font-weight: bold;
    text-transform: uppercase;
    margin-top: 6px;
    color: #5f6b7a;
  }

  .qd-value {
    font-size: 13px;
    margin-top: 4px;
  }

  .qd-chip {
    background-color: #f0f3f6;
    padding: 4px 10px;
    border-radius: 10px;
    font-size: 11px;
    display: inline-block;
  }

  .totals td {
    font-weight: bold;
    background-color: #eef4f6;
  }

  .qd-terms {
    margin-top: 16px;
    padding: 12px;
    border: 1px dashed #c9d3d6;
  }
</style>

<div class="qd-content">

  <!-- HEADER -->
  <table>
    <tr class="qd-header-row">
      <td width="60%">
        <div class="qd-title">Quotation</div>
        <div class="qd-subtitle">Prepared for your review</div>
      </td>
      <td width="40%" class="qd-meta">
        <div><strong>ID:</strong> {{ doc.name }}</div>
        <div><strong>Date:</strong> {{ doc.transaction_date }}</div>
        <div><strong>Valid Till:</strong> {{ doc.valid_till }}</div>
      </td>
    </tr>
  </table>

  <br>

  <!-- CUSTOMER -->
  <table>
    <tr>
      <td width="50%" class="qd-card">
        <div class="qd-label">Customer</div>
        <div class="qd-value">{{ doc.party_name }}</div>

        <div class="qd-label">Name</div>
        <div class="qd-value">{{ doc.customer_name }}</div>

        <div class="qd-label">Mobile No</div>
        <div class="qd-value">{{ doc.contact_mobile or "" }}</div>
      </td>

      <td width="50%" class="qd-card">
        <div class="qd-label">Address</div>
        <div class="qd-value">{{ doc.shipping_address or "" }}</div>

        <div class="qd-label">Status</div>
        <div class="qd-value">
          <span class="qd-chip">{{ doc.status }}</span>
        </div>
      </td>
    </tr>
  </table>

  <br>

  <!-- ITEMS TABLE (FIXED GREEN HEADER) -->
  <table>
    <tr>
      <td width="24%" style="background:#2e7d32;color:#fff;font-weight:bold;">Item Name</td>
      <td width="18%" style="background:#2e7d32;color:#fff;font-weight:bold;">Generic Name</td>
      <td width="10%" style="background:#2e7d32;color:#fff;font-weight:bold;">UOM</td>
      <td width="8%"  style="background:#2e7d32;color:#fff;font-weight:bold;" class="right">Qty</td>
      <td width="14%" style="background:#2e7d32;color:#fff;font-weight:bold;" class="right">Rate</td>
      <td width="16%" style="background:#2e7d32;color:#fff;font-weight:bold;" class="right">Amount</td>
    </tr>

    {% for item in doc.items %}
      {% set generic_name = frappe.db.get_value("Item", item.item_code, "custom_genric_name") or "" %}
      <tr>
        <td>{{ item.item_name }}</td>
        <td>{{ generic_name }}</td>
        <td>{{ item.uom }}</td>
        <td class="right">{{ item.qty }}</td>
        <td class="right">{{ frappe.utils.fmt_money(item.rate, currency=currency) }}</td>
        <td class="right">{{ frappe.utils.fmt_money(item.amount, currency=currency) }}</td>
      </tr>
    {% endfor %}
  </table>

  <br>

  <!-- TOTALS -->
  <table>
    <tr class="totals">
      <td width="70%" class="right">Net Total</td>
      <td width="30%" class="right">{{ frappe.utils.fmt_money(doc.net_total, currency=currency) }}</td>
    </tr>
    <tr class="totals">
      <td class="right">Taxes and Charges</td>
      <td class="right">{{ frappe.utils.fmt_money(doc.total_taxes_and_charges, currency=currency) }}</td>
    </tr>
    <tr class="totals">
      <td class="right">Grand Total</td>
      <td class="right">{{ frappe.utils.fmt_money(doc.grand_total, currency=currency) }}</td>
    </tr>
  </table>

  <!-- TERMS -->
  <div class="qd-terms">
    <div class="qd-label">Terms</div>
    <div class="qd-value">{{ doc.terms or "" }}</div>
  </div>

</div>

